408→#[cfg(test)]
409→mod tests {
410→    use super::*;
411→
412→    #[test]
413→    fn test_parse_comment() {
414→        let src = "; this is a comment\n";
415→        let m = parse(src, "test.spc").unwrap();
416→        assert_eq!(m.items.len(), 1);
417→        assert_eq!(m.items[0], Item::Comment("; this is a comment".to_string()));
418→    }
