420→    #[test]
421→    fn test_parse_global() {
422→        let src = ".global count 1\n";
423→        let m = parse(src, "test.spc").unwrap();
424→        assert_eq!(m.items.len(), 1);
425→        assert_eq!(
426→            m.items[0],
427→            Item::Global(Global {
428→                name: "count".to_string(),
429→                nwords: 1
430→            })
431→        );
432→    }
