434→    #[test]
435→    fn test_parse_data() {
436→        let src = ".data msg 72, 101, 108, 108, 111, 10, 0\n";
437→        let m = parse(src, "test.spc").unwrap();
438→        assert_eq!(m.items.len(), 1);
439→        match &m.items[0] {
440→            Item::Data(d) => {
441→                assert_eq!(d.name, "msg");
442→                assert_eq!(d.bytes, vec![72, 101, 108, 108, 111, 10, 0]);
443→            }
444→            _ => panic!("expected Data"),
445→        }
446→    }
