448→    #[test]
449→    fn test_parse_const() {
450→        let src = ".const MAX 255\n";
451→        let m = parse(src, "test.spc").unwrap();
452→        assert_eq!(m.items.len(), 1);
453→        assert_eq!(
454→            m.items[0],
455→            Item::Const(Const {
456→                name: "MAX".to_string(),
457→                value: "255".to_string()
458→            })
459→        );
460→    }
