462→    #[test]
463→    fn test_parse_simple_proc() {
464→        let src = "\
465→.proc main 0
466→    push 42
467→    halt
468→.end
469→";
470→        let m = parse(src, "test.spc").unwrap();
471→        assert_eq!(m.items.len(), 1);
472→        match &m.items[0] {
473→            Item::Proc(p) => {
474→                assert_eq!(p.name, "main");
475→                assert_eq!(p.nlocals, 0);
476→                assert_eq!(p.body.len(), 2);
477→                assert_eq!(
478→                    p.body[0],
479→                    Statement::Instruction(Instruction {
480→                        mnemonic: "push".to_string(),
481→                        operand: Some("42".to_string()),
482→                        comment: None,
483→                    })
484→                );
485→                assert_eq!(
486→                    p.body[1],
487→                    Statement::Instruction(Instruction {
488→                        mnemonic: "halt".to_string(),
489→                        operand: None,
490→                        comment: None,
491→                    })
492→                );
493→            }
494→            _ => panic!("expected Proc"),
495→        }
496→    }
