498→    #[test]
499→    fn test_parse_proc_with_labels() {
500→        let src = "\
501→.proc puts 1
502→    loada 0
503→    storel 0
504→loop:
505→    loadl 0
506→    loadb
507→    dup
508→    jz done
509→    sys 1
510→    jmp loop
511→done:
512→    drop
513→    ret 1
514→.end
515→";
516→        let m = parse(src, "test.spc").unwrap();
517→        match &m.items[0] {
518→            Item::Proc(p) => {
519→                assert_eq!(p.name, "puts");
520→                assert_eq!(p.nlocals, 1);
521→                // Check that labels are parsed
522→                assert!(p.body.iter().any(|s| *s == Statement::Label("loop".to_string())));
523→                assert!(p.body.iter().any(|s| *s == Statement::Label("done".to_string())));
524→            }
525→            _ => panic!("expected Proc"),
526→        }
527→    }
