529→    #[test]
530→    fn test_parse_instruction_with_comment() {
531→        let src = "\
532→.proc test 0
533→    push 45              ; '-'
534→    sys 1                ; PUTC
535→.end
536→";
537→        let m = parse(src, "test.spc").unwrap();
538→        match &m.items[0] {
539→            Item::Proc(p) => {
540→                match &p.body[0] {
541→                    Statement::Instruction(i) => {
542→                        assert_eq!(i.mnemonic, "push");
543→                        assert_eq!(i.operand.as_deref(), Some("45"));
544→                        assert!(i.comment.as_ref().unwrap().contains("'-'"));
545→                    }
546→                    _ => panic!("expected instruction"),
547→                }
548→            }
549→            _ => panic!("expected Proc"),
550→        }
551→    }
