553→    #[test]
554→    fn test_parse_hello_spc() {
555→        let src = "\
556→; hello.spc — Hello World for pv24a P-Code VM
557→;
558→; Expected output: Hello\\n
559→
560→.data msg 72, 101, 108, 108, 111, 10, 0
561→
562→.proc main 0
563→    push msg
564→    call puts
565→    halt
566→.end
567→
568→.proc puts 1
569→    loada 0
570→    storel 0
571→loop:
572→    loadl 0
573→    loadb
574→    dup
575→    jz done
576→    sys 1
577→    loadl 0
578→    push 1
579→    add
580→    storel 0
581→    jmp loop
582→done:
583→    drop
584→    ret 1
585→.end
586→";
587→        let m = parse(src, "hello.spc").unwrap();
588→        assert_eq!(m.name, "hello");
589→        assert!(!m.has_metadata);
590→        assert!(m.exports.is_empty());
591→        assert!(m.externs.is_empty());
592→
593→        // Should have: 3 comments, 1 data, 2 procs = 6 items
594→        assert_eq!(m.items.len(), 6);
595→
596→        // Verify data
597→        match &m.items[3] {
598→            Item::Data(d) => {
599→                assert_eq!(d.name, "msg");
600→                assert_eq!(d.bytes, vec![72, 101, 108, 108, 111, 10, 0]);
601→            }
602→            _ => panic!("expected Data at index 3"),
603→        }
604→
605→        // Verify main proc
606→        match &m.items[4] {
607→            Item::Proc(p) => {
608→                assert_eq!(p.name, "main");
609→                assert_eq!(p.nlocals, 0);
610→            }
611→            _ => panic!("expected Proc at index 4"),
612→        }
613→    }
