692→    #[test]
693→    fn test_parse_runtime_spc() {
694→        let src = "\
695→; pr24p — Pascal Runtime Library
696→; Phase 0: Hand-written .spc stubs
697→
698→.proc _p24p_write_int 1
699→    enter 1
700→    loada 0
701→    dup
702→    push 0
703→    lt
704→    jz positive
705→    push 45
706→    sys 1
707→    neg
708→positive:
709→    storel 0
710→    push 0
711→extract:
