  1→//! Core linker for pl24r — the COR24 p-code linker.
  2→//!
  3→//! Merges multiple parsed .spc modules into a single linked output,
  4→//! ordering modules correctly and merging declarations by type.
  5→//! Language-agnostic: operates on .spc files from any COR24 compiler frontend.
  6→
  7→use crate::parser::{Const, Data, Global, Item, Module, Proc, Statement};
  8→
  9→/// The merged output of linking multiple .spc modules.
 10→#[derive(Debug, Clone, PartialEq)]
 11→pub struct LinkedOutput {
 12→    /// Header comments (preserved from all modules).
 13→    pub comments: Vec<String>,
 14→    /// Merged global declarations.
 15→    pub globals: Vec<Global>,
 16→    /// Merged data declarations.
 17→    pub data: Vec<Data>,
 18→    /// Merged constant declarations.
 19→    pub consts: Vec<Const>,
 20→    /// All procedures in link order (runtime/libs first, main module last).
 21→    pub procs: Vec<Proc>,
 22→}
 23→
 24→/// Error encountered during linking.
 25→#[derive(Debug, Clone, PartialEq)]
 26→pub struct LinkError {
 27→    pub message: String,
 28→}
 29→
 30→impl std::fmt::Display for LinkError {
 31→    fn fmt(&self, f: &mut std::fmt::Formatter<'_>) -> std::fmt::Result {
 32→        write!(f, "{}", self.message)
 33→    }
 34→}
 35→
 36→impl std::error::Error for LinkError {}
 37→
 38→/// Link multiple parsed modules into a single merged output.
 39→///
 40→/// Modules are reordered: modules without `main` come first (in input order),
 41→/// then the module containing `main` comes last as the entry point.
 42→/// Linker-only metadata (.module, .endmodule, .export, .extern) is stripped.
 43→pub fn link(modules: &[Module]) -> Result<LinkedOutput, Vec<LinkError>> {
 44→    let mut errors = Vec::new();
 45→
 46→    // Find the app module (contains main).
 47→    let main_index = modules
 48→        .iter()
 49→        .position(|m| m.items.iter().any(|item| matches!(item, Item::Proc(p) if p.name == "main")));
 50→
 51→    let Some(main_index) = main_index else {
 52→        errors.push(LinkError {
 53→            message: "no module contains a 'main' procedure".to_string(),
 54→        });
 55→        return Err(errors);
 56→    };
 57→
 58→    // Order: all non-main modules in input order, then main module last.
 59→    let mut ordered: Vec<&Module> = Vec::with_capacity(modules.len());
 60→    for (i, m) in modules.iter().enumerate() {
 61→        if i != main_index {
 62→            ordered.push(m);
 63→        }
 64→    }
 65→    ordered.push(&modules[main_index]);
 66→
 67→    let mut comments = Vec::new();
 68→    let mut globals = Vec::new();
 69→    let mut data = Vec::new();
 70→    let mut consts = Vec::new();
 71→    let mut procs = Vec::new();
 72→
 73→    let mut seen_globals = std::collections::HashSet::new();
 74→    let mut seen_consts = std::collections::HashMap::new();
 75→
 76→    for module in &ordered {
 77→        // Add a module separator comment for debuggability.
 78→        comments.push(format!("; --- module: {} ---", module.name));
 79→
 80→        for item in &module.items {
 81→            match item {
 82→                Item::Comment(c) => comments.push(c.clone()),
 83→                Item::Global(g) => {
 84→                    if seen_globals.insert(g.name.clone()) {
 85→                        globals.push(g.clone());
 86→                    }
 87→                    // Duplicate globals with same name are silently merged
 88→                    // (symbol table already validated no conflicts).
 89→                }
 90→                Item::Data(d) => {
 91→                    data.push(d.clone());
 92→                }
 93→                Item::Const(c) => {
 94→                    if let Some(prev_val) = seen_consts.get(&c.name) {
 95→                        if *prev_val != c.value {
 96→                            errors.push(LinkError {
 97→                                message: format!(
 98→                                    "conflicting constant '{}': '{}' vs '{}'",
 99→                                    c.name, prev_val, c.value
100→                                ),
101→                            });
102→                        }
103→                    } else {
104→                        seen_consts.insert(c.name.clone(), c.value.clone());
105→                        consts.push(c.clone());
106→                    }
107→                }
108→                Item::Proc(p) => {
109→                    procs.push(p.clone());
110→                }
111→            }
112→        }
113→    }
114→
115→    if !errors.is_empty() {
116→        return Err(errors);
117→    }
118→
119→    Ok(LinkedOutput {
120→        comments,
121→        globals,
122→        data,
123→        consts,
124→        procs,
125→    })
126→}
127→
128→/// Emit a linked output as .spc text, ready for pasm.
129→pub fn emit(output: &LinkedOutput) -> String {
130→    let mut lines = Vec::new();
131→
132→    // Header comments.
133→    for c in &output.comments {
134→        lines.push(c.clone());
135→    }
136→    if !output.comments.is_empty() {
137→        lines.push(String::new());
138→    }
139→
140→    // Globals section.
141→    for g in &output.globals {
142→        lines.push(format!(".global {} {}", g.name, g.nwords));
143→    }
144→    if !output.globals.is_empty() {
145→        lines.push(String::new());
146→    }
147→
148→    // Data section.
149→    for d in &output.data {
150→        let bytes_str: Vec<String> = d.bytes.iter().map(|b| b.to_string()).collect();
151→        lines.push(format!(".data {} {}", d.name, bytes_str.join(",")));
152→    }
153→    if !output.data.is_empty() {
154→        lines.push(String::new());
155→    }
156→
157→    // Constants section.
158→    for c in &output.consts {
159→        lines.push(format!(".const {} {}", c.name, c.value));
160→    }
161→    if !output.consts.is_empty() {
162→        lines.push(String::new());
163→    }
164→
165→    // Procedures.
166→    for p in &output.procs {
167→        lines.push(format!(".proc {} {}", p.name, p.nlocals));
168→        for stmt in &p.body {
169→            match stmt {
170→                Statement::Label(l) => lines.push(format!("{l}:")),
171→                Statement::Instruction(i) => {
172→                    let mut s = format!("    {}", i.mnemonic);
173→                    if let Some(op) = &i.operand {
174→                        s.push(' ');
175→                        s.push_str(op);
176→                    }
177→                    if let Some(c) = &i.comment {
178→                        // Pad to align comments.
179→                        let pad = if s.len() < 24 { 24 - s.len() } else { 1 };
180→                        s.push_str(&" ".repeat(pad));
181→                        s.push_str(c);
182→                    }
183→                    lines.push(s);
184→                }
185→                Statement::Comment(c) => lines.push(format!("    {c}")),
186→                Statement::Blank => lines.push(String::new()),
187→            }
188→        }
189→        lines.push(".end".to_string());
190→        lines.push(String::new());
191→    }
192→
193→    lines.join("\n")
194→}
